class DynamicArray:
    def __init__(self, capacity=1):
        self.capacity = capacity
        self.size = 0
        self.array = [None] * self.capacity

    def __len__(self):
        return self.size

    def append(self, value):
        if self.size == self.capacity:
            self._resize(2 * self.capacity)
        self.array[self.size] = value
        self.size += 1

    def _resize(self, new_capacity):
        new_array = [None] * new_capacity
        for i in range(self.size):
            new_array[i] = self.array[i]
        self.array = new_array
        self.capacity = new_capacity
        print(f"Resized to capacity: {new_capacity}")

# Demonstration
arr = DynamicArray()
for i in range(1, 17):
    arr.append(i)
    print(f"Size: {len(arr)}, Capacity: {arr.capacity}")

class BinaryCounter:
    def __init__(self, bits=8):
        self.bits = bits
        self.counter = [0] * bits
        self.num_operations = 0

    def increment(self):
        self.num_operations += 1
        for i in range(self.bits):
            if self.counter[i] == 0:
                self.counter[i] = 1
                break
            else:
                self.counter[i] = 0
        return self.get_value()

    def get_value(self):
        return sum(self.counter[i] * (2 ** i) for i in range(self.bits))

    def display(self):
        return ''.join(map(str, reversed(self.counter)))

# Demonstration with analysis
counter = BinaryCounter(8)
print("Binary Counter - Amortized Analysis Demo")
print("=" * 50)

for i in range(1, 17):
    val = counter.increment()
    flips = 0
    for j in range(8):
        if counter.counter[j] == 0:
            flips += 1
    print(f"Op {i:2d}: Value={val:3d}, Binary={counter.display()}, Bit flips this op")

print(f"\nTotal operations: {counter.num_operations}")
print("Analysis: Over n increments, total bit flips = O(n)")
print("Therefore, amortized cost per increment = O(1)")

class Stack:
    def __init__(self):
        self.items = []

    def push(self, item):
        self.items.append(item)

    def pop(self):
        if not self.is_empty():
            return self.items.pop()
        return None

    def is_empty(self):
        return len(self.items) == 0

    def peek(self):
        return self.items[-1] if not self.is_empty() else None

    def __len__(self):
        return len(self.items)

class QueueWithTwoStacks:
    def __init__(self):
        self.enqueue_stack = Stack()  # For adding elements
        self.dequeue_stack = Stack()   # For removing elements
        self.operation_count = 0

    def enqueue(self, item):
        self.operation_count += 1
        self.enqueue_stack.push(item)

    def dequeue(self):
        self.operation_count += 1
        if self.dequeue_stack.is_empty():
            # Transfer all elements from enqueue to dequeue stack
            while not self.enqueue_stack.is_empty():
                self.dequeue_stack.push(self.enqueue_stack.pop())
        return self.dequeue_stack.pop()

    def front(self):
        if self.dequeue_stack.is_empty():
            while not self.enqueue_stack.is_empty():
                self.dequeue_stack.push(self.enqueue_stack.pop())
        return self.dequeue_stack.peek()

    def is_empty(self):
        return self.enqueue_stack.is_empty() and self.dequeue_stack.is_empty()

    def __len__(self):
        return len(self.enqueue_stack) + len(self.dequeue_stack)

# Demonstration
queue = QueueWithTwoStacks()
print("Queue with Two Stacks - Amortized Analysis")
print("=" * 50)

# Enqueue operations
for i in range(1, 6):
    queue.enqueue(i * 10)
    print(f"Enqueued: {i * 10}, Queue size: {len(queue)}")

# Dequeue operations
print("\nDequeuing elements:")
for _ in range(3):
    val = queue.dequeue()
    print(f"Dequeued: {val}, Queue size: {len(queue)}")

# Add more and dequeue
for i in range(6, 9):
    queue.enqueue(i * 10)
print(f"\nEnqueued 60, 70, 80. Queue size: {len(queue)}")

while not queue.is_empty():
    print(f"Dequeued: {queue.dequeue()}")

print(f"\nTotal operations performed: {queue.operation_count}")
print("Amortized cost: O(1) per operation using accounting method")
